class Solution:
    def largeGroupPositions(self, s: str) -> List[List[int]]:
        result = []
        i = 0
        while i < len(s) - 2:
            if s[i] == s[i + 1] == s[i + 2]:
                result.append([i, i + 2])
                i += 3
            else:
                i += 1
        return result
